import json
import re

# Get the file path from query results
file_path = '/tmp/tmp0x5m5h7q.json'

with open(file_path, 'r') as f:
    business_data = json.load(f)

# Get ratings data
ratings_data = locals()['var_functions.query_db:16']
ratings_dict = {item['gmap_id']: float(item['avg_rating']) for item in ratings_data}

# Function to check if open after 6PM on weekdays
def is_open_after_6pm(hours_str):
    if not hours_str or hours_str == 'None':
        return False

    try:
        # Parse string representation of list
        hours_list = eval(hours_str)
        if not isinstance(hours_list, list):
            return False

        weekdays = {'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'}

        for entry in hours_list:
            if len(entry) != 2:
                continue

            day, time_range = entry
            if day not in weekdays:
                continue

            # Check for 24 hours
            if time_range == 'Open 24 hours':
                return True
            if time_range == 'Closed':
                continue

            # Find dash and extract closing time
            for dash in ['\u2013', '\u2014', '-']:
                if dash in time_range:
                    closing = time_range.split(dash)[1].strip()
                    break
            else:
                continue

            # Check for PM times
            if 'PM' in closing.upper():
                # Extract hour number
                match = re.search(r'(\d{1,2})(?::\d{2})?\s*PM', closing, re.IGNORECASE)
                if match:
                    hour = int(match.group(1))
                    if hour < 12:
                        hour += 12  # Convert to 24-hour format
                    if hour >= 18:  # 6 PM or later
                        return True

        return False
    except:
        return False

# Filter businesses open after 6PM
open_late = []
for business in business_data:
    gmap_id = business.get('gmap_id')
    if not gmap_id:
        continue

    hours = business.get('hours')
    if not hours or hours == 'None':
        continue

    if is_open_after_6pm(hours):
        avg_rating = ratings_dict.get(gmap_id, 0.0)
        if avg_rating > 0:  # Only include businesses with reviews
            open_late.append({
                'name': business['name'],
                'gmap_id': gmap_id,
                'hours': hours,
                'avg_rating': avg_rating
            })

# Sort by rating and get top 5
open_late.sort(key=lambda x: x['avg_rating'], reverse=True)
top_5 = open_late[:5]

# Format results
results = []
for i, biz in enumerate(top_5, 1):
    results.append({
        'rank': i,
        'name': biz['name'],
        'hours': biz['hours'],
        'avg_rating': round(biz['avg_rating'], 2)
    })

print('__RESULT__:')
print(json.dumps(results))

